import * as d3 from "d3"
import { useEffect, useRef } from "react"

const ChartDraw = (props) => {
	const chartRef = useRef(null);

	useEffect(() => {
        const svg = d3.select(chartRef.current);
		svg
		.append("circle")
		.attr("r", 100)
		.attr("cx", 200)
		.attr("cy", 200)
		.style("fill", "red");
	});

    return (
      <svg ref={ chartRef }>  </svg>
    )
}

export default ChartDraw;
